import { useSignal, useSignals } from '@cascivo/core'
import styles from './swap.module.css'

export type SwapMode = 'rotate' | 'flip'

export interface SwapProps {
  on: React.ReactNode
  off: React.ReactNode
  checked?: boolean
  onChange?: (checked: boolean) => void
  mode?: SwapMode
  'aria-label'?: string
  className?: string
}

export function Swap({
  on,
  off,
  checked = false,
  onChange,
  mode = 'rotate',
  className,
  ...aria
}: SwapProps) {
  useSignals()
  const isChecked = useSignal(checked)
  isChecked.value = checked

  function handleClick() {
    const next = !isChecked.value
    onChange?.(next)
  }

  return (
    <button
      type="button"
      role="switch"
      aria-checked={isChecked.value}
      className={[styles.swap, className].filter(Boolean).join(' ')}
      data-checked={isChecked.value || undefined}
      data-mode={mode}
      onClick={handleClick}
      {...aria}
    >
      <span className={styles.on} aria-hidden="true">
        {on}
      </span>
      <span className={styles.off} aria-hidden="true">
        {off}
      </span>
    </button>
  )
}

@layer cascivo.component {
  .swap {
    display: inline-grid;
    grid-template-areas: 'swap';
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    position: relative;
    overflow: hidden;
  }

  .swap:focus-visible {
    outline: var(--cascivo-ring-width) solid var(--cascivo-ring-color);
    outline-offset: 2px;
    border-radius: var(--cascivo-radius-control);
  }

  .on,
  .off {
    grid-area: swap;
    display: flex;
    align-items: center;
    justify-content: center;
    transition-property: transform, opacity;
    transition-duration: 200ms;
    transition-timing-function: var(--cascivo-ease-out);
  }

  .swap[data-mode='rotate'] .on {
    transform: rotate(0deg);
    opacity: 1;
  }
  .swap[data-mode='rotate'] .off {
    transform: rotate(-90deg);
    opacity: 0;
  }
  .swap[data-mode='rotate'][data-checked] .on {
    transform: rotate(90deg);
    opacity: 0;
  }
  .swap[data-mode='rotate'][data-checked] .off {
    transform: rotate(0deg);
    opacity: 1;
  }

  .swap[data-mode='flip'] .on {
    transform: rotateY(0deg);
    opacity: 1;
  }
  .swap[data-mode='flip'] .off {
    transform: rotateY(180deg);
    opacity: 0;
  }
  .swap[data-mode='flip'][data-checked] .on {
    transform: rotateY(-180deg);
    opacity: 0;
  }
  .swap[data-mode='flip'][data-checked] .off {
    transform: rotateY(0deg);
    opacity: 1;
  }
}
